# Generated by GitHub Copilot
def build_event(model_name: str, low_confidence: bool) -> dict[str, object]:
    """Create one synthetic inference event payload."""

    if low_confidence:
        confidence = round(random.uniform(0.2, 0.5), 4)
        latency_ms = round(random.uniform(700, 1400), 2)
        prediction = random.choice(["review", "fallback", "manual"])
    else:
        confidence = round(random.uniform(0.65, 0.98), 4)
        latency_ms = round(random.uniform(40, 320), 2)
        prediction = random.choice(["approved", "accepted", "auto"])

    return {
        "model_name": model_name,
        "latency_ms": latency_ms,
        "prediction": prediction,
        "confidence": confidence,
        "timestamp": datetime.now(timezone.utc).isoformat(),
        "metadata": {
            "source": "demo-load-generator",
            "low_confidence": low_confidence,
        },
    }


# Generated by GitHub Copilot
def send_event(base_url: str, payload: dict[str, object], api_key: str) -> bool:
    """Send one event to POST /log and return True on accepted response."""

    endpoint = base_url.rstrip("/") + "/log"
    headers = {"Content-Type": "application/json"}
    if api_key:
        headers["X-API-Key"] = api_key

    req = request.Request(
        endpoint,
        data=json.dumps(payload).encode("utf-8"),
        headers=headers,
        method="POST",
    )

    try:
        with request.urlopen(req, timeout=15) as response:
            return 200 <= response.status < 300
    except error.HTTPError as exc:
        print(f"HTTP error {exc.code}: {exc.reason}")
        return False
    except error.URLError as exc:
        print(f"Connection error: {exc.reason}")
        return False


