def main() -> int:
    """Run synthetic load generation and print outcome summary."""

    args = build_parser().parse_args()

    if args.events <= 0:
        raise ValueError("--events must be a positive integer")
    if args.sleep_ms < 0:
        raise ValueError("--sleep-ms must be zero or positive")
    if args.drift_ratio < 0.0 or args.drift_ratio > 1.0:
        raise ValueError("--drift-ratio must be between 0 and 1")

    random.seed(args.seed)

    sent = 0
    failed = 0
    low_confidence_events = 0

    for index in range(args.events):
        low_confidence = random.random() < args.drift_ratio
        if low_confidence:
            low_confidence_events += 1

        payload = build_event(args.model_name, low_confidence=low_confidence)
        ok = send_event(args.base_url, payload, api_key=args.api_key)
        if ok:
            sent += 1
        else:
            failed += 1

        if args.sleep_ms > 0 and index < args.events - 1:
            time.sleep(args.sleep_ms / 1000.0)

    print(
        json.dumps(
            {
                "base_url": args.base_url,
                "model_name": args.model_name,
                "requested_events": args.events,
                "sent": sent,
                "failed": failed,
                "low_confidence_events": low_confidence_events,
                "drift_ratio": args.drift_ratio,
            },
            indent=2,
        )
    )

    return 0 if failed == 0 else 1


if __name__ == "__main__":
    raise SystemExit(main())
